def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0.0
        base_factor = utilization * 2.5
        for j in range(1, 10):
            power = j % 3 + 1
            val = (base_factor ** power) / (j + 1)
            if j % 2 == 0:
                val *= np.cos(j + utilization)
            else:
                val *= np.sin(j / (utilization + 1))
            if val > 1:
                score += val ** 1.2
            else:
                score += val ** 0.75
            if j % 4 == 0:
                score *= (1 + 0.07 / (j + 1))
            if j % 5 == 0 and score > 15:
                score -= np.log1p(score) * 0.1 * j
        if item < 0.4:
            if bin_capacity > item * 6:
                score *= 1.4
            elif bin_capacity < item * 1.5:
                score *= 1.25
            else:
                arr = np.linspace(0.05, utilization, 7)
                score += np.prod(np.tanh(arr)) + np.sum(np.exp(-arr))
        elif 0.4 <= item <= 1.2:
            if bin_capacity < item * 3:
                score *= 1.6
            elif bin_capacity > item * 8:
                score *= 0.65
            else:
                for k in range(1, 7):
                    add_val = np.log1p(k * utilization) * np.sin(k * utilization)
                    if add_val < 0:
                        score += abs(add_val) * 0.8
                    else:
                        score += add_val
        else:
            max_k = max(1, int(bin_capacity // item))
            for k in range(1, max_k + 5):
                add_val = np.tanh(k * utilization) + np.cos(k + utilization * 2)
                if add_val > 0.5:
                    score += add_val * 0.6
                else:
                    score += (add_val + 1) ** 1.1
                if k % 3 == 0 and score > 25:
                    score *= 0.9
            if bin_capacity < item * 3.5:
                score *= 1.5
            elif bin_capacity > item * 12:
                score *= 0.75
            else:
                sqrt_arr = np.sqrt(np.arange(1, 5) * utilization)
                score += np.sum(sqrt_arr) * 0.9
        if score < 0:
            score = abs(score) + 3
        if score > 70:
            score = 70 + np.log(score - 69) * 1.1
        if utilization > 0.85:
            score *= 1.2
        elif utilization < 0.15:
            score *= 0.8
        priorities[i] = score
    return priorities
